const industry = $.input.industry;
const queries = [
  { source: 'reddit', query: 'site:reddit.com trending discussions about ' + industry },
  { source: 'news', query: 'latest trending news and developments in ' + industry },
  { source: 'industry', query: 'viral social media content trends for ' + industry + ' 2024 2025' }
];
return { queries };

const queries = $.steps.buildQueries.output.queries;
const iterations = $.steps.searchTrends.response.iterations || [];
let compiled = '';
let totalSources = 0;

queries.forEach((q, i) => {
  const iter = iterations[i];
  const results = (iter && iter.searchSource && iter.searchSource.response && iter.searchSource.response.results) ? iter.searchSource.response.results : [];
  compiled += '=== SOURCE: ' + q.source.toUpperCase() + ' ===\n';
  results.forEach((r, j) => {
    compiled += (j + 1) + '. ' + (r.title || '') + '\n   ' + (r.text || '').slice(0, 800) + '\n\n';
    totalSources++;
  });
});

return { compiled: compiled.slice(0, 25000), totalSources };

const d = $.steps.compileTrends.output;
const industry = $.input.industry;
const platforms = $.input.platforms || 'LinkedIn, Twitter, Instagram';

let prompt = 'You are a social media trend analyst and content strategist. Analyze the following trending topics, score them for relevance, and generate platform-specific content for each top trend.\n\n';
prompt += 'INDUSTRY: ' + industry + '\n';
prompt += 'TARGET PLATFORMS: ' + platforms + '\n\n';
prompt += 'TREND RESEARCH (' + d.totalSources + ' sources):\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Identify the top 5 most relevant trends for the industry\n';
prompt += '- Score each trend 1-10 on relevance, timeliness, and virality\n';
prompt += '- For each top trend, generate content tailored to each target platform\n';
prompt += '- LinkedIn: professional, thought-leadership tone (200-300 words)\n';
prompt += '- Twitter: concise, punchy, thread-worthy (under 280 chars per tweet)\n';
prompt += '- Instagram: visual description + caption (150 words max)\n';
prompt += '- Include hashtags appropriate for each platform\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "trends": [\n';
prompt += '    {\n';
prompt += '      "trendName": "name",\n';
prompt += '      "description": "brief description",\n';
prompt += '      "relevanceScore": 8,\n';
prompt += '      "timelinessScore": 9,\n';
prompt += '      "viralityScore": 7,\n';
prompt += '      "overallScore": 8,\n';
prompt += '      "content": {\n';
prompt += '        "linkedin": { "text": "post text", "hashtags": ["tag"] },\n';
prompt += '        "twitter": { "text": "tweet text", "hashtags": ["tag"] },\n';
prompt += '        "instagram": { "caption": "caption", "visualIdea": "image concept", "hashtags": ["tag"] }\n';
prompt += '      }\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "weeklyCalendar": [{ "day": "Monday", "platform": "LinkedIn", "trendIndex": 0, "postingTime": "9:00 AM" }],\n';
prompt += '  "strategyNotes": "overall content strategy advice"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { trends: [], weeklyCalendar: [], strategyNotes: raw }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);
const rows = [];
rows.push(['Date', 'Trend', 'Score', 'Platform', 'Content', 'Hashtags', 'Status']);
(ai.trends || []).forEach(t => {
  const content = t.content || {};
  if (content.linkedin) {
    rows.push([today, t.trendName, String(t.overallScore || ''), 'LinkedIn', (content.linkedin.text || '').slice(0, 1500), (content.linkedin.hashtags || []).join(', '), 'Draft']);
  }
  if (content.twitter) {
    rows.push([today, t.trendName, String(t.overallScore || ''), 'Twitter', (content.twitter.text || '').slice(0, 500), (content.twitter.hashtags || []).join(', '), 'Draft']);
  }
  if (content.instagram) {
    rows.push([today, t.trendName, String(t.overallScore || ''), 'Instagram', (content.instagram.caption || '').slice(0, 1000), (content.instagram.hashtags || []).join(', '), 'Draft']);
  }
});
return { rows, rowCount: rows.length - 1 };

const ai = $.steps.parseAI.output;
const rows = $.steps.buildSheetRows.output;
const industry = $.input.industry;

let body = 'Social Content Calendar - ' + industry + '\n\n';
body += 'Trends Analyzed: ' + (ai.trends || []).length + '\n';
body += 'Content Pieces Generated: ' + rows.rowCount + '\n\n';
(ai.trends || []).forEach((t, i) => {
  body += (i + 1) + '. ' + t.trendName + ' (Score: ' + (t.overallScore || 'N/A') + ')\n';
  body += '   ' + (t.description || '') + '\n\n';
});
if (ai.strategyNotes) body += 'Strategy: ' + ai.strategyNotes + '\n';
body += '\nFull content calendar saved to Google Sheets.\n';
body += '\n---\nGenerated by One CLI + Claude AI';

const subject = 'Social Content Calendar: ' + industry + ' - ' + new Date().toISOString().slice(0, 10);
return { body, subject };

const ai = $.steps.parseAI.output;
const rows = $.steps.buildSheetRows.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Social Content Calendar Ready', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Industry:* ' + $.input.industry + ' | *Trends:* ' + (ai.trends || []).length + ' | *Content Pieces:* ' + rows.rowCount } });
blocks.push({ type: 'divider' });

(ai.trends || []).slice(0, 5).forEach((t, i) => {
  const scoreEmoji = (t.overallScore || 0) >= 8 ? ':fire:' : (t.overallScore || 0) >= 6 ? ':chart_with_upwards_trend:' : ':seedling:';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: scoreEmoji + ' *' + t.trendName + '* (Score: ' + (t.overallScore || 'N/A') + ')\n' + (t.description || '').slice(0, 300) } });
});

if (ai.strategyNotes) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Strategy:* ' + ai.strategyNotes.slice(0, 500) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Saved to Sheets + emailed to ' + $.input.emailRecipient + ' | One CLI' }] });
const fallback = 'Social Content: ' + (ai.trends || []).length + ' trends, ' + rows.rowCount + ' pieces for ' + $.input.industry;
return { blocks, fallback };
